import React, { useState, useEffect } from 'react';
import { ShoppingCart } from 'lucide-react';
import { validateCartAddition } from '../utils/cartHelpers';
import Carrito from './Carrito';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];
    
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      
      const ofertasMapeadas = ofertasLocal.map(o => ({
        ...o,
        // Generamos una KEY única combinando local y producto para evitar el error de React
        keyUnica: `local-${local.id}-prod-${o.id}`,
        localId: local.id,
        nombreLocal: local.nombre,
        direccionLocal: local.direccion,
        ciudad: local.ciudad
      }));
      
      acumulador = [...acumulador, ...ofertasMapeadas];
    });
    setTodasLasOfertas(acumulador);
  }, []);

  const agregarAlCarrito = (producto) => {
    // Usamos 'delivery' por defecto para la validación de peso/cantidad
    const check = validateCartAddition(cart, producto, 'delivery');
    if (!check.valid) return alert(check.msg);

    // Al agregar al carrito, le damos un ID de instancia único para que no choque en la lista del carrito
    setCart([...cart, { ...producto, instanceId: Date.now() + Math.random() }]);
  };

  const finalizarCompra = () => {
    alert("¡Compra realizada con éxito! El local ha recibido tu pedido.");
    setCart([]);
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '40px 5%', background: '#f8fafc', minHeight: '100vh' }}>
      
      <div style={{ flex: 1 }}>
        <h2 style={{ marginBottom: '25px', color: '#1e293b' }}>Ofertas Disponibles</h2>
        <div style={grid}>
          {todasLasOfertas.length > 0 ? todasLasOfertas.map(o => (
            // Usamos la keyUnica que generamos arriba
            <div key={o.keyUnica} style={card}>
              <div style={cardBody}>
                <span style={label}>{o.nombreLocal}</span>
                <h3 style={titleStyle}>{o.producto}</h3>
                <p style={pesoTag}>{o.peso} kg</p>
                <div style={priceRow}>
                  <span style={price}>${o.precioNuevo}</span>
                  <button onClick={() => agregarAlCarrito(o)} style={btnAdd}>
                    <ShoppingCart size={18} />
                  </button>
                </div>
              </div>
            </div>
          )) : (
            <p style={{ color: '#64748b' }}>No hay ofertas disponibles en este momento.</p>
          )}
        </div>
      </div>

      {cart.length > 0 && (
        <Carrito 
          cart={cart} 
          setCart={setCart} 
          onCheckout={finalizarCompra} 
        />
      )}
    </div>
  );
};

// --- ESTILOS CORREGIDOS (Evitando conflictos de Shorthand) ---
const grid = { 
  display: 'grid', 
  gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', 
  gap: '20px' 
};

const card = { 
  background: 'white', 
  borderRadius: '15px', 
  borderWidth: '1px',
  borderStyle: 'solid',
  borderColor: '#e2e8f0',
  overflow: 'hidden' 
};

const cardBody = { padding: '15px' };

const label = { 
  fontSize: '0.7rem', 
  fontWeight: 'bold', 
  color: '#e67e22', 
  textTransform: 'uppercase' 
};

const titleStyle = { 
  margin: '5px 0', 
  fontSize: '1.1rem', 
  color: '#1e293b' 
};

const pesoTag = { 
  fontSize: '0.8rem', 
  color: '#94a3b8', 
  marginBottom: '10px' 
};

const priceRow = { 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center' 
};

const price = { 
  fontSize: '1.4rem', 
  fontWeight: 'bold', 
  color: '#1e293b' 
};

const btnAdd = { 
  background: '#1e293b', 
  color: 'white', 
  border: 'none', 
  padding: '10px', 
  borderRadius: '10px', 
  cursor: 'pointer' 
};

export default PanelCliente;
